    '"feedback_record": ', $$recordString, ', ',
    '"coding_levels": {"root_codes": ', $$codesString, '}, ',
    '"max_codes": 1, ',
    '"confidence_threshold": 0.1 ',
    '}'
);","cid":0,"id":"zd0ab95zol","type":"executeFormula"}],"description":null},{"startId":"y07beybblv","endId":"qmgzrskmcs","startDirection":"r","id":"0uz7rzab71","type":"flow"},{"startId":"qmgzrskmcs","endId":"g3dcslcmvk","startDirection":"r","id":"gcab1wb179","type":"flow"},{"startId":"g3dcslcmvk","endId":"7k24bkfmi6","startDirection":"r","id":"gdhv4nbhqw","type":"flow"},{"type":"gatewayParallel","center":{"x":440,"y":320},"id":"bm8zp61qws"},{"startId":"7k24bkfmi6","endId":"bm8zp61qws","startDirection":"d","id":"sc624v1bq9","type":"flow"},{"type":"task","center":{"x":220,"y":420},"id":"k52l9j71wk","text":"summarize","actionList":[{"requestType":"POST","contentType":"application/json","content":"{}","requestUrl":"https://qfa-dev-backend.azurewebsites.net/v1/summarize","headers":["ngrok-skip-browser-warning: 69420","Authorization: Bearer {#secrets.QFA_API_KEY}"],"contentVariable":"$motherPayload","cid":0,"id":"olk7wnmk17","type":"sendRequest"},{"formula":"$response = $_lastHttpResponseBody;

